DES and 3DES are **critically unsafe** for encrypting sensitive data. DES was broken decades ago with its 56-bit key, and 3DES, while having a larger key, uses a 64-bit block size making it vulnerable to the Sweet32 birthday attack (CVE-2016-2183). NIST officially deprecated 3DES in 2017 and disallowed it after 2023.

**VULNERABLE CODE**:

```javascript
const crypto = require('crypto');

// DANGEROUS: Using deprecated 3DES encryption
function encryptUserData(plaintext, secretKey) {
  // 3DES uses 24-byte key (168 bits, but effective security ~112 bits)
  const key = crypto.scryptSync(secretKey, 'salt', 24);

  // VULNERABLE: 3DES with 64-bit block size
  const cipher = crypto.createCipheriv('des-ede3-cbc', key, Buffer.alloc(8));

  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  return encrypted;
}

function decryptUserData(ciphertext, secretKey) {
  const key = crypto.scryptSync(secretKey, 'salt', 24);
  const decipher = crypto.createDecipheriv('des-ede3-cbc', key, Buffer.alloc(8));

  let decrypted = decipher.update(ciphertext, 'hex', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

// Usage
const userData = JSON.stringify({ ssn: '123-45-6789', creditCard: '4111111111111111' });
const encrypted = encryptUserData(userData, 'mysecretpassword');
console.log('Encrypted:', encrypted);
```

**Attack Scenario**:
```text
Sweet32 Birthday Attack:
1. Attacker captures ~32GB of encrypted HTTPS traffic using 3DES
2. With 2^32 blocks (each 8 bytes), collision probability reaches ~50%
3. When two blocks encrypt to same ciphertext, XOR reveals plaintext
4. Repeated patterns in HTTP headers accelerate the attack
5. Sensitive data like session cookies can be recovered in hours
```

**Why This Is Dangerous**:
- **64-bit block size**: Birthday bound is 2^32 blocks (~32GB), achievable in hours of traffic capture
- **DES key size (56-bit)**: Can be brute-forced in under 24 hours with modern hardware
- **3DES effective security (~112-bit)**: Below modern 128-bit minimum requirement
- **Static IV**: Using `Buffer.alloc(8)` creates zero IV, enabling pattern analysis
- **No authentication**: Ciphertext can be modified without detection (malleability attacks)

**SECURE VERSION**:

```javascript
const crypto = require('crypto');

const ALGORITHM = 'aes-256-gcm';  // AES-256 with Galois/Counter Mode
const KEY_LENGTH = 32;            // 256 bits
const IV_LENGTH = 12;             // 96 bits for GCM (NIST recommended)
const AUTH_TAG_LENGTH = 16;       // 128-bit authentication tag
const SALT_LENGTH = 16;           // 128-bit salt

function encryptUserData(plaintext, password) {
  // Generate cryptographically secure random salt and IV
  const salt = crypto.randomBytes(SALT_LENGTH);
  const iv = crypto.randomBytes(IV_LENGTH);

  // Derive key using scrypt with secure parameters
  const key = crypto.scryptSync(password, salt, KEY_LENGTH, {
    N: 2 ** 17,  // CPU/memory cost parameter (131072)
    r: 8,        // Block size
    p: 1         // Parallelization
  });

  // Create cipher with AES-256-GCM
  const cipher = crypto.createCipheriv(ALGORITHM, key, iv, {
    authTagLength: AUTH_TAG_LENGTH
  });

  // Encrypt the data
  let encrypted = cipher.update(plaintext, 'utf8');
  encrypted = Buffer.concat([encrypted, cipher.final()]);

  // Get authentication tag (provides integrity)
  const authTag = cipher.getAuthTag();

  // Combine: salt + iv + authTag + ciphertext
  const result = Buffer.concat([salt, iv, authTag, encrypted]);

  return result.toString('base64');
}

function decryptUserData(encryptedData, password) {
  const data = Buffer.from(encryptedData, 'base64');

  // Extract components
  const salt = data.subarray(0, SALT_LENGTH);
  const iv = data.subarray(SALT_LENGTH, SALT_LENGTH + IV_LENGTH);
  const authTag = data.subarray(SALT_LENGTH + IV_LENGTH, SALT_LENGTH + IV_LENGTH + AUTH_TAG_LENGTH);
  const ciphertext = data.subarray(SALT_LENGTH + IV_LENGTH + AUTH_TAG_LENGTH);

  // Derive key with same parameters
  const key = crypto.scryptSync(password, salt, KEY_LENGTH, {
    N: 2 ** 17,
    r: 8,
    p: 1
  });

  // Create decipher and set auth tag
  const decipher = crypto.createDecipheriv(ALGORITHM, key, iv, {
    authTagLength: AUTH_TAG_LENGTH
  });
  decipher.setAuthTag(authTag);

  // Decrypt and verify integrity
  let decrypted = decipher.update(ciphertext);
  decrypted = Buffer.concat([decrypted, decipher.final()]);

  return decrypted.toString('utf8');
}

// Usage
const userData = JSON.stringify({ ssn: '123-45-6789', creditCard: '4111111111111111' });
const encrypted = encryptUserData(userData, 'mysecretpassword');
console.log('Encrypted:', encrypted);
const decrypted = decryptUserData(encrypted, 'mysecretpassword');
console.log('Decrypted:', decrypted);
```

**Key Security Controls**:
- **AES-256-GCM**: 128-bit block size (birthday bound 2^64, requires exabytes), 256-bit key, AEAD mode
- **Random IV per encryption**: Prevents pattern analysis; GCM requires unique IV per key
- **Authentication tag**: Detects tampering; decryption fails if ciphertext modified
- **Strong key derivation**: scrypt with high cost factor resists brute-force attacks
- **Random salt**: Prevents rainbow table attacks on password-derived keys

Migrating from legacy encryption requires careful planning to maintain data availability while upgrading security. Here's a production-ready migration strategy with backward compatibility:

**PRODUCTION PATTERN**:

```javascript
const crypto = require('crypto');
const winston = require('winston');

// Configure secure logging (no sensitive data)
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'crypto-migration.log' })
  ]
});

// Encryption algorithm versions for migration tracking
const CRYPTO_VERSIONS = {
  V1_DES: 0x01,      // DEPRECATED: DES-CBC (legacy)
  V2_3DES: 0x02,     // DEPRECATED: 3DES-CBC (legacy)
  V3_AES_GCM: 0x03   // CURRENT: AES-256-GCM
};

const CURRENT_VERSION = CRYPTO_VERSIONS.V3_AES_GCM;

// Security constants
const AES_KEY_LENGTH = 32;
const AES_IV_LENGTH = 12;
const AUTH_TAG_LENGTH = 16;
const SALT_LENGTH = 16;

class SecureEncryptionService {
  constructor(options = {}) {
    this.allowLegacyDecrypt = options.allowLegacyDecrypt || false;
    this.migrationMode = options.migrationMode || false;
    this.keyDerivationParams = {
      N: 2 ** 17,
      r: 8,
      p: 1
    };

    // Track migration metrics
    this.metrics = {
      legacyDecryptions: 0,
      modernEncryptions: 0,
      migrationCount: 0,
      failedOperations: 0
    };
  }

  // Modern AES-256-GCM encryption (always use for new data)
  encrypt(plaintext, password) {
    try {
      const salt = crypto.randomBytes(SALT_LENGTH);
      const iv = crypto.randomBytes(AES_IV_LENGTH);

      const key = crypto.scryptSync(password, salt, AES_KEY_LENGTH, this.keyDerivationParams);

      const cipher = crypto.createCipheriv('aes-256-gcm', key, iv, {
        authTagLength: AUTH_TAG_LENGTH
      });

      let encrypted = cipher.update(plaintext, 'utf8');
      encrypted = Buffer.concat([encrypted, cipher.final()]);
      const authTag = cipher.getAuthTag();

      // Format: version(1) + salt(16) + iv(12) + authTag(16) + ciphertext
      const result = Buffer.concat([
        Buffer.from([CURRENT_VERSION]),
        salt,
        iv,
        authTag,
        encrypted
      ]);

      this.metrics.modernEncryptions++;
      logger.info('Encryption completed', { 
        version: 'AES-256-GCM',
        dataLength: plaintext.length 
      });

      return result.toString('base64');
    } catch (error) {
      this.metrics.failedOperations++;
      logger.error('Encryption failed', { error: error.message });
      throw new Error('Encryption operation failed');
    }
  }

  // Multi-version decryption with automatic detection
  decrypt(encryptedData, password, legacyKey = null) {
    try {
      const data = Buffer.from(encryptedData, 'base64');
      const version = data[0];

      switch (version) {
        case CRYPTO_VERSIONS.V3_AES_GCM:
          return this._decryptAESGCM(data, password);

        case CRYPTO_VERSIONS.V2_3DES:
          if (!this.allowLegacyDecrypt) {
            throw new Error('Legacy 3DES decryption disabled - data migration required');
          }
          logger.warn('Legacy 3DES decryption attempted', { 
            action: 'SECURITY_AUDIT',
            recommendation: 'Re-encrypt with AES-256-GCM'
          });
          this.metrics.legacyDecryptions++;
          return this._decryptLegacy3DES(data, legacyKey || password);

        case CRYPTO_VERSIONS.V1_DES:
          if (!this.allowLegacyDecrypt) {
            throw new Error('Legacy DES decryption disabled - immediate migration required');
          }
          logger.error('CRITICAL: DES decryption attempted', {
            action: 'SECURITY_ALERT',
            severity: 'CRITICAL'
          });
          this.metrics.legacyDecryptions++;
          return this._decryptLegacyDES(data, legacyKey || password);

        default:
          throw new Error('Unknown encryption version');
      }
    } catch (error) {
      this.metrics.failedOperations++;
      logger.error('Decryption failed', { error: error.message });
      throw error;
    }
  }

  // Migrate data from legacy to modern encryption
  async migrateRecord(encryptedData, oldPassword, newPassword) {
    try {
      // Temporarily enable legacy decryption for migration
      const originalSetting = this.allowLegacyDecrypt;
      this.allowLegacyDecrypt = true;

      // Decrypt with legacy algorithm
      const plaintext = this.decrypt(encryptedData, oldPassword);

      // Re-encrypt with modern algorithm
      const newEncrypted = this.encrypt(plaintext, newPassword);

      this.allowLegacyDecrypt = originalSetting;
      this.metrics.migrationCount++;

      logger.info('Record migration completed', {
        action: 'MIGRATION_SUCCESS',
        fromVersion: this._detectVersion(encryptedData),
        toVersion: 'AES-256-GCM'
      });

      return newEncrypted;
    } catch (error) {
      logger.error('Migration failed', { error: error.message });
      throw new Error('Migration operation failed');
    }
  }

  // Batch migration with progress tracking
  async batchMigrate(records, oldPassword, newPassword, progressCallback) {
    const results = {
      success: 0,
      failed: 0,
      errors: []
    };

    for (let i = 0; i < records.length; i++) {
      try {
        const migrated = await this.migrateRecord(
          records[i].encryptedData,
          oldPassword,
          newPassword
        );
        records[i].encryptedData = migrated;
        records[i].cryptoVersion = CURRENT_VERSION;
        results.success++;
      } catch (error) {
        results.failed++;
        results.errors.push({ index: i, error: error.message });
      }

      if (progressCallback) {
        progressCallback((i + 1) / records.length * 100);
      }
    }

    logger.info('Batch migration completed', results);
    return results;
  }

  // Private: Modern AES-GCM decryption
  _decryptAESGCM(data, password) {
    const salt = data.subarray(1, 1 + SALT_LENGTH);
    const iv = data.subarray(1 + SALT_LENGTH, 1 + SALT_LENGTH + AES_IV_LENGTH);
    const authTag = data.subarray(
      1 + SALT_LENGTH + AES_IV_LENGTH,
      1 + SALT_LENGTH + AES_IV_LENGTH + AUTH_TAG_LENGTH
    );
    const ciphertext = data.subarray(1 + SALT_LENGTH + AES_IV_LENGTH + AUTH_TAG_LENGTH);

    const key = crypto.scryptSync(password, salt, AES_KEY_LENGTH, this.keyDerivationParams);

    const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv, {
      authTagLength: AUTH_TAG_LENGTH
    });
    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(ciphertext);
    decrypted = Buffer.concat([decrypted, decipher.final()]);

    return decrypted.toString('utf8');
  }

  // Private: Legacy 3DES decryption (for migration only)
  _decryptLegacy3DES(data, password) {
    const iv = data.subarray(1, 9);
    const ciphertext = data.subarray(9);

    const key = crypto.scryptSync(password, 'legacy-salt', 24);
    const decipher = crypto.createDecipheriv('des-ede3-cbc', key, iv);

    let decrypted = decipher.update(ciphertext);
    decrypted = Buffer.concat([decrypted, decipher.final()]);

    return decrypted.toString('utf8');
  }

  // Private: Legacy DES decryption (for migration only)
  _decryptLegacyDES(data, password) {
    const iv = data.subarray(1, 9);
    const ciphertext = data.subarray(9);

    const key = crypto.scryptSync(password, 'legacy-salt', 8);
    const decipher = crypto.createDecipheriv('des-cbc', key, iv);

    let decrypted = decipher.update(ciphertext);
    decrypted = Buffer.concat([decrypted, decipher.final()]);

    return decrypted.toString('utf8');
  }

  _detectVersion(encryptedData) {
    const data = Buffer.from(encryptedData, 'base64');
    const versionMap = {
      [CRYPTO_VERSIONS.V1_DES]: 'DES-CBC',
      [CRYPTO_VERSIONS.V2_3DES]: '3DES-CBC',
      [CRYPTO_VERSIONS.V3_AES_GCM]: 'AES-256-GCM'
    };
    return versionMap[data[0]] || 'Unknown';
  }

  getMetrics() {
    return { ...this.metrics };
  }
}

// Express middleware for automatic re-encryption
function cryptoMigrationMiddleware(encryptionService) {
  return async (req, res, next) => {
    if (req.body && req.body.encryptedData) {
      const data = Buffer.from(req.body.encryptedData, 'base64');
      const version = data[0];

      if (version < CURRENT_VERSION) {
        // Flag for migration
        req.needsCryptoMigration = true;
        req.cryptoVersion = version;

        logger.warn('Legacy encryption detected in request', {
          version: version,
          endpoint: req.path,
          action: 'MIGRATION_NEEDED'
        });
      }
    }
    next();
  };
}

module.exports = {
  SecureEncryptionService,
  cryptoMigrationMiddleware,
  CRYPTO_VERSIONS
};
```

**Defense in Depth Layers**:

1. **Version-Tagged Encryption Format**:
```javascript
// Every encrypted blob starts with version byte
// Format: [VERSION(1)] + [ALGORITHM_SPECIFIC_DATA]
// Enables automatic algorithm detection and migration tracking
const result = Buffer.concat([
  Buffer.from([CURRENT_VERSION]),  // Version tag
  salt,                             // Random salt
  iv,                               // Random IV
  authTag,                          // Authentication tag
  encrypted                         // Ciphertext
]);
```

2. **Legacy Algorithm Quarantine**:
```javascript
// Disable legacy decryption by default
const service = new SecureEncryptionService({
  allowLegacyDecrypt: false,  // Fail-safe: block weak crypto
  migrationMode: false
});

// Only enable temporarily during controlled migration
service.allowLegacyDecrypt = true;
const plaintext = service.decrypt(legacyData, password);
service.allowLegacyDecrypt = false;  // Immediately re-disable
```

3. **Comprehensive Audit Logging**:
```javascript
// Log all crypto operations for compliance and incident response
logger.warn('Legacy 3DES decryption attempted', { 
  action: 'SECURITY_AUDIT',
  timestamp: new Date().toISOString(),
  recommendation: 'Re-encrypt with AES-256-GCM',
  pciDssReference: 'Requirement 3.6.1'
});
```

**Additional Protections**:

- **Key Rotation Support**: Version tagging allows phased key rotation without data loss
- **Metrics Collection**: Track migration progress and detect legacy crypto usage patterns
- **Fail-Secure Design**: Unknown versions or tampered data throws errors rather than attempting unsafe operations
- **Compliance Documentation**: Logging supports PCI DSS, HIPAA, and SOC 2 audit requirements
- **Gradual Migration Path**: Batch migration with progress callbacks for large datasets
- **Middleware Integration**: Automatic detection of legacy-encrypted data in API requests

**No, DES and Triple-DES (3DES) are NOT safe for encrypting payment data or any sensitive information.** DES was broken decades ago, and 3DES has been deprecated by NIST since 2017 due to the Sweet32 birthday attack (CVE-2016-2183). Using these algorithms puts you at risk of PCI-DSS non-compliance and potential data breaches.

**VULNERABLE CODE**:

```java
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.SecretKeySpec;
import java.util.Base64;

public class InsecurePaymentEncryption {

    // DANGEROUS: Using deprecated DES algorithm
    private static final String ALGORITHM = "DES";

    public String encryptPaymentData(String creditCardNumber, byte[] keyBytes) throws Exception {
        // VULNERABLE: DES has only 56-bit key strength
        SecretKeySpec key = new SecretKeySpec(keyBytes, ALGORITHM);

        // VULNERABLE: ECB mode leaks patterns in ciphertext
        Cipher cipher = Cipher.getInstance("DES/ECB/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, key);

        byte[] encrypted = cipher.doFinal(creditCardNumber.getBytes("UTF-8"));
        return Base64.getEncoder().encodeToString(encrypted);
    }

    // Also vulnerable: Triple-DES with 64-bit block size
    public String encrypt3DES(String data, byte[] keyBytes) throws Exception {
        SecretKeySpec key = new SecretKeySpec(keyBytes, "DESede");
        // VULNERABLE: 64-bit blocks enable Sweet32 birthday attacks
        Cipher cipher = Cipher.getInstance("DESede/CBC/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, key);

        byte[] encrypted = cipher.doFinal(data.getBytes("UTF-8"));
        return Base64.getEncoder().encodeToString(encrypted);
    }
}
```

**Attack Scenario**:
```text
Sweet32 Attack on 3DES:
1. Attacker captures encrypted HTTPS traffic using 3DES
2. After ~32GB of data (2^32 blocks), birthday collision occurs
3. XOR of two colliding ciphertext blocks reveals XOR of plaintexts
4. Combined with known plaintext (HTTP headers), secrets are recovered

DES Brute Force:
1. 56-bit key space = 2^56 possible keys
2. Modern GPUs test 10^12 keys/second
3. Full key search in ~20 hours with specialized hardware
4. Cloud-based cracking services available for <$100
```

**Why This Is Dangerous**:
- **DES 56-bit keys**: Brute-forceable in hours with modern hardware ($100 in cloud compute)
- **64-bit block size**: Birthday attacks recover plaintext after ~32GB encrypted under same key
- **ECB mode**: Identical plaintext blocks produce identical ciphertext, leaking data patterns
- **No authentication**: Ciphertext can be modified without detection
- **PCI-DSS Violation**: DES/3DES explicitly prohibited for new implementations

**SECURE VERSION**:

```java
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;
import java.util.Arrays;
import java.util.Base64;

public class SecurePaymentEncryption {

    // SECURE: AES-256 with authenticated encryption
    private static final String ALGORITHM = "AES";
    private static final String TRANSFORMATION = "AES/GCM/NoPadding";
    private static final int GCM_IV_LENGTH = 12;  // 96 bits recommended for GCM
    private static final int GCM_TAG_LENGTH = 128; // Authentication tag bits
    private static final int AES_KEY_SIZE = 256;   // 256-bit key strength

    private final SecureRandom secureRandom = new SecureRandom();

    public SecretKey generateKey() throws Exception {
        KeyGenerator keyGen = KeyGenerator.getInstance(ALGORITHM);
        keyGen.init(AES_KEY_SIZE, secureRandom);
        return keyGen.generateKey();
    }

    public String encryptPaymentData(String creditCardNumber, SecretKey key) throws Exception {
        // Generate unique IV for each encryption
        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);

        // SECURE: AES-GCM provides confidentiality AND authenticity
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.ENCRYPT_MODE, key, gcmSpec);

        byte[] encrypted = cipher.doFinal(creditCardNumber.getBytes("UTF-8"));

        // Prepend IV to ciphertext for decryption
        byte[] combined = new byte[iv.length + encrypted.length];
        System.arraycopy(iv, 0, combined, 0, iv.length);
        System.arraycopy(encrypted, 0, combined, iv.length, encrypted.length);

        return Base64.getEncoder().encodeToString(combined);
    }

    public String decryptPaymentData(String encryptedData, SecretKey key) throws Exception {
        byte[] combined = Base64.getDecoder().decode(encryptedData);

        // Extract IV and ciphertext
        byte[] iv = Arrays.copyOfRange(combined, 0, GCM_IV_LENGTH);
        byte[] ciphertext = Arrays.copyOfRange(combined, GCM_IV_LENGTH, combined.length);

        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.DECRYPT_MODE, key, gcmSpec);

        // GCM automatically verifies authenticity
        byte[] decrypted = cipher.doFinal(ciphertext);
        return new String(decrypted, "UTF-8");
    }
}
```

**Key Security Controls**:
- **AES-256**: 256-bit keys are computationally infeasible to brute force (2^256 operations)
- **GCM Mode**: Provides authenticated encryption - detects any tampering with ciphertext
- **128-bit blocks**: Immune to Sweet32 birthday attacks (would require 2^64 blocks)
- **Unique IVs**: Fresh random IV per encryption prevents pattern analysis
- **Integrated authentication**: GCM tag ensures data integrity without separate HMAC

Excellent questions! Key management and streaming encryption are critical for production systems. Poor key handling undermines even the strongest encryption, and memory-efficient streaming is essential for large datasets.

**PRODUCTION PATTERN**:

```java
import javax.crypto.*;
import javax.crypto.spec.*;
import java.io.*;
import java.nio.ByteBuffer;
import java.nio.channels.FileChannel;
import java.security.*;
import java.util.Arrays;
import java.util.Base64;
import java.util.logging.Logger;

public class ProductionCryptoService {

    private static final Logger AUDIT_LOG = Logger.getLogger("security.audit.crypto");
    private static final String TRANSFORMATION = "AES/GCM/NoPadding";
    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;
    private static final int BUFFER_SIZE = 8192; // 8KB chunks for streaming

    private final SecureRandom secureRandom;
    private final KeyManagementService keyManager;

    public ProductionCryptoService(KeyManagementService keyManager) {
        this.keyManager = keyManager;
        this.secureRandom = new SecureRandom();
    }

    /**
     * Encrypt sensitive data with envelope encryption pattern.
     * Data Encryption Key (DEK) is encrypted by Key Encryption Key (KEK).
     */
    public EncryptedPayload encryptWithEnvelope(byte[] plaintext, String keyId) 
            throws GeneralSecurityException {

        // Generate ephemeral DEK for this data
        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        keyGen.init(256, secureRandom);
        SecretKey dataKey = keyGen.generateKey();

        // Encrypt the data with DEK
        byte[] iv = generateIV();
        byte[] ciphertext = encryptAESGCM(plaintext, dataKey, iv);

        // Wrap DEK with KEK from key management system
        SecretKey masterKey = keyManager.getKey(keyId);
        byte[] wrappedKey = wrapKey(dataKey, masterKey);

        // Clear DEK from memory immediately
        clearKey(dataKey);

        AUDIT_LOG.info(String.format(
            "Encrypted %d bytes with key_id=%s, iv_prefix=%s",
            plaintext.length, keyId, Base64.getEncoder().encodeToString(Arrays.copyOf(iv, 4))
        ));

        return new EncryptedPayload(wrappedKey, iv, ciphertext, keyId);
    }

    /**
     * Stream encryption for large files - memory efficient.
     * Uses AES-GCM with chunked processing.
     */
    public void encryptFileStream(File inputFile, File outputFile, String keyId) 
            throws IOException, GeneralSecurityException {

        long startTime = System.currentTimeMillis();

        // Generate DEK and IV
        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        keyGen.init(256, secureRandom);
        SecretKey dataKey = keyGen.generateKey();
        byte[] iv = generateIV();

        // Wrap DEK with master key
        SecretKey masterKey = keyManager.getKey(keyId);
        byte[] wrappedKey = wrapKey(dataKey, masterKey);

        try (FileInputStream fis = new FileInputStream(inputFile);
             FileOutputStream fos = new FileOutputStream(outputFile)) {

            // Write header: key_id_length(4) + key_id + wrapped_key_length(4) + wrapped_key + iv
            writeHeader(fos, keyId, wrappedKey, iv);

            // Initialize cipher for streaming
            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.ENCRYPT_MODE, dataKey, gcmSpec);

            // Process file in chunks
            byte[] buffer = new byte[BUFFER_SIZE];
            int bytesRead;
            long totalBytesProcessed = 0;

            while ((bytesRead = fis.read(buffer)) != -1) {
                byte[] output = cipher.update(buffer, 0, bytesRead);
                if (output != null) {
                    fos.write(output);
                }
                totalBytesProcessed += bytesRead;
            }

            // Write final block with GCM tag
            byte[] finalBlock = cipher.doFinal();
            fos.write(finalBlock);

            // Audit log success
            long duration = System.currentTimeMillis() - startTime;
            AUDIT_LOG.info(String.format(
                "File encrypted: input=%s, output=%s, bytes=%d, duration_ms=%d, key_id=%s",
                inputFile.getName(), outputFile.getName(), totalBytesProcessed, duration, keyId
            ));

        } finally {
            clearKey(dataKey);
        }
    }

    /**
     * Decrypt streaming file with authentication verification.
     */
    public void decryptFileStream(File inputFile, File outputFile) 
            throws IOException, GeneralSecurityException {

        try (FileInputStream fis = new FileInputStream(inputFile);
             FileOutputStream fos = new FileOutputStream(outputFile)) {

            // Read header
            EncryptedFileHeader header = readHeader(fis);

            // Unwrap DEK using master key
            SecretKey masterKey = keyManager.getKey(header.keyId);
            SecretKey dataKey = unwrapKey(header.wrappedKey, masterKey);

            try {
                // Initialize cipher
                Cipher cipher = Cipher.getInstance(TRANSFORMATION);
                GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, header.iv);
                cipher.init(Cipher.DECRYPT_MODE, dataKey, gcmSpec);

                // Decrypt in chunks
                byte[] buffer = new byte[BUFFER_SIZE];
                int bytesRead;

                while ((bytesRead = fis.read(buffer)) != -1) {
                    byte[] output = cipher.update(buffer, 0, bytesRead);
                    if (output != null) {
                        fos.write(output);
                    }
                }

                // Verify GCM tag and write final block
                // Throws AEADBadTagException if tampered
                byte[] finalBlock = cipher.doFinal();
                fos.write(finalBlock);

                AUDIT_LOG.info(String.format(
                    "File decrypted successfully: file=%s, key_id=%s",
                    inputFile.getName(), header.keyId
                ));

            } catch (AEADBadTagException e) {
                AUDIT_LOG.severe(String.format(
                    "SECURITY ALERT: Authentication failed for file=%s - possible tampering!",
                    inputFile.getName()
                ));
                // Delete partial output to prevent use of corrupted data
                outputFile.delete();
                throw new SecurityException("Data integrity verification failed", e);
            } finally {
                clearKey(dataKey);
            }
        }
    }

    private byte[] generateIV() {
        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);
        return iv;
    }

    private byte[] encryptAESGCM(byte[] plaintext, SecretKey key, byte[] iv) 
            throws GeneralSecurityException {
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.ENCRYPT_MODE, key, gcmSpec);
        return cipher.doFinal(plaintext);
    }

    private byte[] wrapKey(SecretKey keyToWrap, SecretKey wrappingKey) 
            throws GeneralSecurityException {
        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        byte[] iv = generateIV();
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.WRAP_MODE, wrappingKey, gcmSpec);
        byte[] wrapped = cipher.wrap(keyToWrap);

        // Combine IV + wrapped key
        byte[] result = new byte[iv.length + wrapped.length];
        System.arraycopy(iv, 0, result, 0, iv.length);
        System.arraycopy(wrapped, 0, result, iv.length, wrapped.length);
        return result;
    }

    private SecretKey unwrapKey(byte[] wrappedKeyData, SecretKey wrappingKey) 
            throws GeneralSecurityException {
        byte[] iv = Arrays.copyOfRange(wrappedKeyData, 0, GCM_IV_LENGTH);
        byte[] wrapped = Arrays.copyOfRange(wrappedKeyData, GCM_IV_LENGTH, wrappedKeyData.length);

        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.UNWRAP_MODE, wrappingKey, gcmSpec);
        return (SecretKey) cipher.unwrap(wrapped, "AES", Cipher.SECRET_KEY);
    }

    private void clearKey(SecretKey key) {
        try {
            // Attempt to clear key material from memory
            if (key instanceof Destroyable) {
                ((Destroyable) key).destroy();
            }
        } catch (DestroyFailedException e) {
            // Log but continue - not all key implementations support destroy
            AUDIT_LOG.warning("Could not destroy key material: " + e.getMessage());
        }
    }

    private void writeHeader(OutputStream os, String keyId, byte[] wrappedKey, byte[] iv) 
            throws IOException {
        DataOutputStream dos = new DataOutputStream(os);
        byte[] keyIdBytes = keyId.getBytes("UTF-8");
        dos.writeInt(keyIdBytes.length);
        dos.write(keyIdBytes);
        dos.writeInt(wrappedKey.length);
        dos.write(wrappedKey);
        dos.write(iv);
    }

    private EncryptedFileHeader readHeader(InputStream is) throws IOException {
        DataInputStream dis = new DataInputStream(is);
        int keyIdLength = dis.readInt();
        byte[] keyIdBytes = new byte[keyIdLength];
        dis.readFully(keyIdBytes);
        String keyId = new String(keyIdBytes, "UTF-8");

        int wrappedKeyLength = dis.readInt();
        byte[] wrappedKey = new byte[wrappedKeyLength];
        dis.readFully(wrappedKey);

        byte[] iv = new byte[GCM_IV_LENGTH];
        dis.readFully(iv);

        return new EncryptedFileHeader(keyId, wrappedKey, iv);
    }

    // Data classes
    public static class EncryptedPayload {
        public final byte[] wrappedKey;
        public final byte[] iv;
        public final byte[] ciphertext;
        public final String keyId;

        public EncryptedPayload(byte[] wrappedKey, byte[] iv, byte[] ciphertext, String keyId) {
            this.wrappedKey = wrappedKey;
            this.iv = iv;
            this.ciphertext = ciphertext;
            this.keyId = keyId;
        }
    }

    private static class EncryptedFileHeader {
        final String keyId;
        final byte[] wrappedKey;
        final byte[] iv;

        EncryptedFileHeader(String keyId, byte[] wrappedKey, byte[] iv) {
            this.keyId = keyId;
            this.wrappedKey = wrappedKey;
            this.iv = iv;
        }
    }
}

