Triple DES (3DES) is **NOT secure** for modern applications. It was officially deprecated by NIST in 2017 and disallowed for new applications as of 2024. The 64-bit block size makes it vulnerable to the Sweet32 birthday attack (CVE-2016-2183), where an attacker can recover plaintext after capturing ~32GB of ciphertext.

**VULNERABLE CODE**:

```go
package main

import (
	"crypto/cipher"
	"crypto/des"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"io"
)

// VULNERABLE: Using 3DES with 64-bit block size
func encryptWith3DES(plaintext []byte, key []byte) (string, error) {
	// 3DES requires 24-byte key (three 8-byte DES keys)
	block, err := des.NewTripleDESCipher(key)
	if err != nil {
		return "", err
	}

	// VULNERABLE: 64-bit IV is too small
	iv := make([]byte, des.BlockSize) // Only 8 bytes!
	if _, err := io.ReadFull(rand.Reader, iv); err != nil {
		return "", err
	}

	// Pad plaintext to block size
	padded := pkcs7Pad(plaintext, des.BlockSize)

	ciphertext := make([]byte, len(padded))
	mode := cipher.NewCBCEncrypter(block, iv)
	mode.CryptBlocks(ciphertext, padded)

	// Prepend IV to ciphertext
	result := append(iv, ciphertext...)
	return hex.EncodeToString(result), nil
}

func pkcs7Pad(data []byte, blockSize int) []byte {
	padLen := blockSize - (len(data) % blockSize)
	padding := make([]byte, padLen)
	for i := range padding {
		padding[i] = byte(padLen)
	}
	return append(data, padding...)
}

func main() {
	key := []byte("123456789012345678901234") // 24-byte key for 3DES
	plaintext := []byte("Credit Card: 4111-1111-1111-1111")

	encrypted, _ := encryptWith3DES(plaintext, key)
	fmt.Println("Encrypted:", encrypted)
}
```

**Attack Scenario**:
```text
Sweet32 Birthday Attack:
1. Attacker captures encrypted traffic (e.g., HTTPS session cookies)
2. After ~2^32 blocks (32GB), birthday collision occurs
3. XOR of two colliding ciphertext blocks reveals XOR of plaintexts
4. Known plaintext portions allow recovery of secret data

Complexity: 2^32 operations (practical with modern hardware)
Time: Hours to days depending on traffic volume
```

**Why This Is Dangerous**:
- 64-bit block size allows birthday attacks after 2^32 blocks (~32GB)
- DES key space is only 56 bits (brute-forceable in hours)
- 3DES provides only 112-bit effective security, not 168-bit as often claimed
- No longer compliant with PCI DSS, HIPAA, or NIST standards
- Modern CPUs lack hardware acceleration for DES/3DES

**SECURE VERSION**:

```go
package main

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/hex"
	"errors"
	"fmt"
	"io"
)

// SECURE: Using AES-256-GCM with 128-bit block size and authenticated encryption
func encryptWithAESGCM(plaintext []byte, key []byte) (string, error) {
	// Validate key length (32 bytes for AES-256)
	if len(key) != 32 {
		return "", errors.New("key must be 32 bytes for AES-256")
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		return "", fmt.Errorf("failed to create cipher: %w", err)
	}

	// GCM provides authenticated encryption
	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return "", fmt.Errorf("failed to create GCM: %w", err)
	}

	// Generate random 96-bit nonce (recommended for GCM)
	nonce := make([]byte, aesGCM.NonceSize()) // 12 bytes
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return "", fmt.Errorf("failed to generate nonce: %w", err)
	}

	// Encrypt and authenticate (nonce prepended to ciphertext)
	ciphertext := aesGCM.Seal(nonce, nonce, plaintext, nil)

	return hex.EncodeToString(ciphertext), nil
}

func decryptWithAESGCM(ciphertextHex string, key []byte) ([]byte, error) {
	if len(key) != 32 {
		return nil, errors.New("key must be 32 bytes for AES-256")
	}

	ciphertext, err := hex.DecodeString(ciphertextHex)
	if err != nil {
		return nil, fmt.Errorf("invalid ciphertext encoding: %w", err)
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, fmt.Errorf("failed to create cipher: %w", err)
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return nil, fmt.Errorf("failed to create GCM: %w", err)
	}

	nonceSize := aesGCM.NonceSize()
	if len(ciphertext) < nonceSize {
		return nil, errors.New("ciphertext too short")
	}

	nonce, ciphertext := ciphertext[:nonceSize], ciphertext[nonceSize:]

	// Decrypt and verify authentication tag
	plaintext, err := aesGCM.Open(nil, nonce, ciphertext, nil)
	if err != nil {
		return nil, errors.New("decryption failed: authentication error")
	}

	return plaintext, nil
}

func main() {
	// Generate secure random key (in production, use proper key management)
	key := make([]byte, 32)
	if _, err := io.ReadFull(rand.Reader, key); err != nil {
		panic(err)
	}

	plaintext := []byte("Credit Card: 4111-1111-1111-1111")

	encrypted, err := encryptWithAESGCM(plaintext, key)
	if err != nil {
		panic(err)
	}
	fmt.Println("Encrypted:", encrypted)

	decrypted, err := decryptWithAESGCM(encrypted, key)
	if err != nil {
		panic(err)
	}
	fmt.Println("Decrypted:", string(decrypted))
}
