**Key Security Controls**:
- **AES-256-GCM**: 128-bit block size immune to Sweet32, provides confidentiality AND integrity
- **Authenticated Encryption**: GCM mode detects tampering, preventing chosen-ciphertext attacks
- **Proper Nonce Generation**: Cryptographically random 96-bit nonces prevent nonce reuse attacks
- **Hardware Acceleration**: AES-NI instructions provide 10x+ performance vs 3DES

Migrating from 3DES to AES requires careful planning to avoid data loss and maintain security during the transition. Here's a production-ready approach with proper key management:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/des"
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"encoding/hex"
	"errors"
	"fmt"
	"io"
	"log"
	"os"
	"sync"
	"time"

	"golang.org/x/crypto/hkdf"
)

// CipherVersion tracks encryption algorithm versions
type CipherVersion byte

const (
	VersionLegacy3DES CipherVersion = 0x01 // Deprecated, read-only
	VersionAES256GCM  CipherVersion = 0x02 // Current standard
)

// EncryptedData contains versioned encrypted data
type EncryptedData struct {
	Version    CipherVersion
	KeyID      string // For key rotation tracking
	Ciphertext []byte
}

// KeyManager handles secure key storage and rotation
type KeyManager struct {
	mu              sync.RWMutex
	currentKeyID    string
	keys            map[string][]byte // KeyID -> Key
	legacy3DESKey   []byte            // For migration only
	keyDeriveSalt   []byte
	rotationPeriod  time.Duration
	lastRotation    time.Time
	auditLog        *log.Logger
}

// NewKeyManager creates a production key manager
func NewKeyManager(masterSecret []byte, auditLog *log.Logger) (*KeyManager, error) {
	if len(masterSecret) < 32 {
		return nil, errors.New("master secret must be at least 32 bytes")
	}

	salt := make([]byte, 32)
	if _, err := io.ReadFull(rand.Reader, salt); err != nil {
		return nil, fmt.Errorf("failed to generate salt: %w", err)
	}

	km := &KeyManager{
		keys:           make(map[string][]byte),
		keyDeriveSalt:  salt,
		rotationPeriod: 90 * 24 * time.Hour, // 90 days
		auditLog:       auditLog,
	}

	// Derive initial key using HKDF
	initialKey, keyID, err := km.deriveKey(masterSecret, "initial-key-v1")
	if err != nil {
		return nil, err
	}

	km.keys[keyID] = initialKey
	km.currentKeyID = keyID
	km.lastRotation = time.Now()

	km.auditLog.Printf("KeyManager initialized with key ID: %s", keyID)

	return km, nil
}

// deriveKey derives an AES-256 key using HKDF
func (km *KeyManager) deriveKey(secret []byte, info string) ([]byte, string, error) {
	hkdfReader := hkdf.New(sha256.New, secret, km.keyDeriveSalt, []byte(info))

	key := make([]byte, 32) // AES-256
	if _, err := io.ReadFull(hkdfReader, key); err != nil {
		return nil, "", fmt.Errorf("HKDF key derivation failed: %w", err)
	}

	// Generate key ID from key hash (first 8 bytes)
	keyHash := sha256.Sum256(key)
	keyID := hex.EncodeToString(keyHash[:8])

	return key, keyID, nil
}

// SetLegacyKey sets the legacy 3DES key for migration
func (km *KeyManager) SetLegacyKey(key []byte) error {
	if len(key) != 24 {
		return errors.New("3DES key must be 24 bytes")
	}
	km.mu.Lock()
	defer km.mu.Unlock()
	km.legacy3DESKey = key
	km.auditLog.Printf("SECURITY: Legacy 3DES key loaded for migration")
	return nil
}

// CryptoService provides encryption/decryption with migration support
type CryptoService struct {
	km       *KeyManager
	auditLog *log.Logger
}

// NewCryptoService creates a new crypto service
func NewCryptoService(km *KeyManager, auditLog *log.Logger) *CryptoService {
	return &CryptoService{
		km:       km,
		auditLog: auditLog,
	}
}

// Encrypt encrypts data using AES-256-GCM (current standard)
func (cs *CryptoService) Encrypt(ctx context.Context, plaintext []byte) (*EncryptedData, error) {
	cs.km.mu.RLock()
	key := cs.km.keys[cs.km.currentKeyID]
	keyID := cs.km.currentKeyID
	cs.km.mu.RUnlock()

	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, fmt.Errorf("cipher creation failed: %w", err)
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return nil, fmt.Errorf("GCM creation failed: %w", err)
	}

	nonce := make([]byte, aesGCM.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return nil, fmt.Errorf("nonce generation failed: %w", err)
	}

	ciphertext := aesGCM.Seal(nonce, nonce, plaintext, nil)

	cs.auditLog.Printf("Encrypt: keyID=%s, size=%d", keyID, len(plaintext))

	return &EncryptedData{
		Version:    VersionAES256GCM,
		KeyID:      keyID,
		Ciphertext: ciphertext,
	}, nil
}

// Decrypt decrypts data, automatically handling legacy 3DES migration
func (cs *CryptoService) Decrypt(ctx context.Context, data *EncryptedData) ([]byte, bool, error) {
	needsMigration := false

	switch data.Version {
	case VersionLegacy3DES:
		// LEGACY: Decrypt with 3DES (read-only, for migration)
		plaintext, err := cs.decryptLegacy3DES(data.Ciphertext)
		if err != nil {
			cs.auditLog.Printf("SECURITY WARNING: Legacy 3DES decryption failed")
			return nil, false, err
		}
		needsMigration = true
		cs.auditLog.Printf("MIGRATION: Decrypted legacy 3DES data, needs re-encryption")
		return plaintext, needsMigration, nil

	case VersionAES256GCM:
		plaintext, err := cs.decryptAESGCM(data)
		if err != nil {
			return nil, false, err
		}
		// Check if key rotation is needed
		cs.km.mu.RLock()
		needsMigration = data.KeyID != cs.km.currentKeyID
		cs.km.mu.RUnlock()
		return plaintext, needsMigration, nil

	default:
		return nil, false, errors.New("unknown cipher version")
	}
}

// decryptLegacy3DES handles legacy 3DES decryption (for migration only)
func (cs *CryptoService) decryptLegacy3DES(ciphertext []byte) ([]byte, error) {
	cs.km.mu.RLock()
	key := cs.km.legacy3DESKey
	cs.km.mu.RUnlock()

	if key == nil {
		return nil, errors.New("legacy 3DES key not configured")
	}

	if len(ciphertext) < des.BlockSize {
		return nil, errors.New("ciphertext too short")
	}

	block, err := des.NewTripleDESCipher(key)
	if err != nil {
		return nil, err
	}

	iv := ciphertext[:des.BlockSize]
	ciphertext = ciphertext[des.BlockSize:]

	if len(ciphertext)%des.BlockSize != 0 {
		return nil, errors.New("ciphertext not aligned to block size")
	}

	mode := cipher.NewCBCDecrypter(block, iv)
	plaintext := make([]byte, len(ciphertext))
	mode.CryptBlocks(plaintext, ciphertext)

	// Remove PKCS7 padding
	return pkcs7Unpad(plaintext)
}

func pkcs7Unpad(data []byte) ([]byte, error) {
	if len(data) == 0 {
		return nil, errors.New("empty data")
	}
	padLen := int(data[len(data)-1])
	if padLen > len(data) || padLen > des.BlockSize {
		return nil, errors.New("invalid padding")
	}
	for i := len(data) - padLen; i < len(data); i++ {
		if data[i] != byte(padLen) {
			return nil, errors.New("invalid padding")
		}
	}
	return data[:len(data)-padLen], nil
}

// decryptAESGCM decrypts AES-256-GCM data
func (cs *CryptoService) decryptAESGCM(data *EncryptedData) ([]byte, error) {
	cs.km.mu.RLock()
	key, exists := cs.km.keys[data.KeyID]
	cs.km.mu.RUnlock()

	if !exists {
		return nil, fmt.Errorf("key not found: %s", data.KeyID)
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonceSize := aesGCM.NonceSize()
	if len(data.Ciphertext) < nonceSize {
		return nil, errors.New("ciphertext too short")
	}

	nonce, ciphertext := data.Ciphertext[:nonceSize], data.Ciphertext[nonceSize:]

	plaintext, err := aesGCM.Open(nil, nonce, ciphertext, nil)
	if err != nil {
		cs.auditLog.Printf("SECURITY: AES-GCM authentication failed for keyID=%s", data.KeyID)
		return nil, errors.New("decryption failed: authentication error")
	}

	return plaintext, nil
}

// MigrateRecord re-encrypts data with current algorithm and key
func (cs *CryptoService) MigrateRecord(ctx context.Context, data *EncryptedData) (*EncryptedData, error) {
	plaintext, _, err := cs.Decrypt(ctx, data)
	if err != nil {
		return nil, fmt.Errorf("migration decrypt failed: %w", err)
	}

	newData, err := cs.Encrypt(ctx, plaintext)
	if err != nil {
		return nil, fmt.Errorf("migration encrypt failed: %w", err)
	}

	cs.auditLog.Printf("MIGRATION: Upgraded from version %d to %d", data.Version, newData.Version)
	return newData, nil
}

func main() {
	auditLog := log.New(os.Stdout, "[CRYPTO-AUDIT] ", log.LstdFlags|log.LUTC)

	// In production: load from secure vault (HashiCorp Vault, AWS KMS, etc.)
	masterSecret := make([]byte, 64)
	if _, err := io.ReadFull(rand.Reader, masterSecret); err != nil {
		panic(err)
	}

	km, err := NewKeyManager(masterSecret, auditLog)
	if err != nil {
		panic(err)
	}

	// Set legacy key for migration (load from secure storage)
	legacy3DESKey := []byte("123456789012345678901234")
	if err := km.SetLegacyKey(legacy3DESKey); err != nil {
		panic(err)
	}

	cs := NewCryptoService(km, auditLog)

	// Simulate legacy encrypted data
	legacyData := &EncryptedData{
		Version:    VersionLegacy3DES,
		KeyID:      "legacy",
		Ciphertext: createLegacy3DESData([]byte("Sensitive PII Data"), legacy3DESKey),
	}

	// Decrypt and migrate
	ctx := context.Background()
	plaintext, needsMigration, err := cs.Decrypt(ctx, legacyData)
	if err != nil {
		panic(err)
	}

	fmt.Printf("Decrypted: %s\n", plaintext)
	fmt.Printf("Needs migration: %v\n", needsMigration)

	if needsMigration {
		migratedData, err := cs.MigrateRecord(ctx, legacyData)
		if err != nil {
			panic(err)
		}
		fmt.Printf("Migrated to version: %d, keyID: %s\n", migratedData.Version, migratedData.KeyID)
	}
}

// Helper: create legacy 3DES encrypted data for testing
func createLegacy3DESData(plaintext, key []byte) []byte {
	block, _ := des.NewTripleDESCipher(key)
	iv := make([]byte, des.BlockSize)
	rand.Read(iv)

	padLen := des.BlockSize - (len(plaintext) % des.BlockSize)
	padded := make([]byte, len(plaintext)+padLen)
	copy(padded, plaintext)
	for i := len(plaintext); i < len(padded); i++ {
		padded[i] = byte(padLen)
	}

	ciphertext := make([]byte, len(padded))
	mode := cipher.NewCBCEncrypter(block, iv)
	mode.CryptBlocks(ciphertext, padded)

	return append(iv, ciphertext...)
}
