using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Logging;

namespace ProductionCrypto
{
    public sealed class AuthenticatedEncryptionService : IDisposable
    {
        private const int KeySizeBytes = 32;      // AES-256
        private const int NonceSizeBytes = 12;    // GCM recommended nonce size
        private const int TagSizeBytes = 16;      // 128-bit authentication tag
        private const int SaltSizeBytes = 32;
        private const int Iterations = 100000;
        private const int VersionByte = 0x01;     // Crypto versioning for future upgrades

        private readonly ILogger<AuthenticatedEncryptionService> _logger;
        private readonly byte[] _masterKey;
        private bool _disposed;

        public AuthenticatedEncryptionService(byte[] masterKey, ILogger<AuthenticatedEncryptionService> logger)
        {
            if (masterKey == null || masterKey.Length != KeySizeBytes)
                throw new ArgumentException($"Master key must be exactly {KeySizeBytes} bytes", nameof(masterKey));

            _masterKey = new byte[KeySizeBytes];
            Array.Copy(masterKey, _masterKey, KeySizeBytes);
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
        }

        /// <summary>
        /// Encrypts data using AES-256-GCM with authenticated encryption
        /// Format: [version(1)][salt(32)][nonce(12)][tag(16)][ciphertext(n)]
        /// </summary>
        public byte[] Encrypt(string plaintext, byte[]? associatedData = null)
        {
            ThrowIfDisposed();

            if (string.IsNullOrEmpty(plaintext))
                throw new ArgumentException("Plaintext cannot be null or empty", nameof(plaintext));

            try
            {
                byte[] salt = RandomNumberGenerator.GetBytes(SaltSizeBytes);
                byte[] nonce = RandomNumberGenerator.GetBytes(NonceSizeBytes);
                byte[] plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
                byte[] ciphertext = new byte[plaintextBytes.Length];
                byte[] tag = new byte[TagSizeBytes];

                // Derive encryption key from master key + salt
                byte[] encryptionKey = DeriveKey(_masterKey, salt, "encryption");

                try
                {
                    using (var aesGcm = new AesGcm(encryptionKey, TagSizeBytes))
                    {
                        aesGcm.Encrypt(nonce, plaintextBytes, ciphertext, tag, associatedData);
                    }

                    // Build output: version + salt + nonce + tag + ciphertext
                    using (var ms = new MemoryStream())
                    {
                        ms.WriteByte(VersionByte);
                        ms.Write(salt, 0, salt.Length);
                        ms.Write(nonce, 0, nonce.Length);
                        ms.Write(tag, 0, tag.Length);
                        ms.Write(ciphertext, 0, ciphertext.Length);

                        _logger.LogDebug("Successfully encrypted {Length} bytes of data", plaintextBytes.Length);
                        return ms.ToArray();
                    }
                }
                finally
                {
                    // Securely clear sensitive data
                    CryptographicOperations.ZeroMemory(encryptionKey);
                    CryptographicOperations.ZeroMemory(plaintextBytes);
                }
            }
            catch (CryptographicException ex)
            {
                _logger.LogError(ex, "Encryption failed");
                throw new InvalidOperationException("Encryption operation failed", ex);
            }
        }

        /// <summary>
        /// Decrypts and authenticates data encrypted with AES-256-GCM
        /// Throws CryptographicException if authentication fails (tampered data)
        /// </summary>
        public string Decrypt(byte[] encryptedData, byte[]? associatedData = null)
        {
            ThrowIfDisposed();

            if (encryptedData == null || encryptedData.Length < 1 + SaltSizeBytes + NonceSizeBytes + TagSizeBytes + 1)
                throw new ArgumentException("Invalid encrypted data format", nameof(encryptedData));

            try
            {
                int offset = 0;

                // Read version byte
                byte version = encryptedData[offset++];
                if (version != VersionByte)
                {
                    _logger.LogWarning("Unsupported encryption version: {Version}", version);
                    throw new NotSupportedException($"Unsupported encryption version: {version}");
                }

                // Extract components
                byte[] salt = new byte[SaltSizeBytes];
                byte[] nonce = new byte[NonceSizeBytes];
                byte[] tag = new byte[TagSizeBytes];
                int ciphertextLength = encryptedData.Length - offset - SaltSizeBytes - NonceSizeBytes - TagSizeBytes;
                byte[] ciphertext = new byte[ciphertextLength];
                byte[] plaintext = new byte[ciphertextLength];

                Array.Copy(encryptedData, offset, salt, 0, SaltSizeBytes);
                offset += SaltSizeBytes;
                Array.Copy(encryptedData, offset, nonce, 0, NonceSizeBytes);
                offset += NonceSizeBytes;
                Array.Copy(encryptedData, offset, tag, 0, TagSizeBytes);
                offset += TagSizeBytes;
                Array.Copy(encryptedData, offset, ciphertext, 0, ciphertextLength);

                byte[] encryptionKey = DeriveKey(_masterKey, salt, "encryption");

                try
                {
                    using (var aesGcm = new AesGcm(encryptionKey, TagSizeBytes))
                    {
                        // This throws CryptographicException if authentication fails
                        aesGcm.Decrypt(nonce, ciphertext, tag, plaintext, associatedData);
                    }

                    _logger.LogDebug("Successfully decrypted and authenticated {Length} bytes", plaintext.Length);
                    return Encoding.UTF8.GetString(plaintext);
                }
                catch (CryptographicException ex)
                {
                    // SECURITY: Don't reveal whether padding or authentication failed
                    _logger.LogWarning(ex, "Decryption authentication failed - possible tampering");
                    throw new CryptographicException("Decryption failed: data may be corrupted or tampered");
                }
                finally
                {
                    CryptographicOperations.ZeroMemory(encryptionKey);
                    CryptographicOperations.ZeroMemory(plaintext);
                }
            }
            catch (CryptographicException)
            {
                throw; // Re-throw crypto exceptions
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error during decryption");
                throw new InvalidOperationException("Decryption operation failed", ex);
            }
        }

        private static byte[] DeriveKey(byte[] masterKey, byte[] salt, string context)
        {
            // Use HKDF for key derivation (available in .NET 5+)
            byte[] contextBytes = Encoding.UTF8.GetBytes(context);
            return HKDF.DeriveKey(HashAlgorithmName.SHA256, masterKey, KeySizeBytes, salt, contextBytes);
        }

        private void ThrowIfDisposed()
        {
            if (_disposed)
                throw new ObjectDisposedException(nameof(AuthenticatedEncryptionService));
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                CryptographicOperations.ZeroMemory(_masterKey);
                _disposed = true;
            }
        }
    }

