      legacy: {
        'des-ede3-cbc': { keyLength: 24, ivLength: 8, deprecated: true },
        'des-cbc': { keyLength: 8, ivLength: 8, deprecated: true }
      },
      modern: {
        'aes-256-gcm': { keyLength: 32, ivLength: 12, tagLength: 16, preferred: true },
        'chacha20-poly1305': { keyLength: 32, ivLength: 12, tagLength: 16 }
      }
    };
  }

  // Key derivation from master key using HKDF
  deriveKey(masterKey, salt, info, keyLength = 32) {
    return crypto.hkdfSync(
      'sha256',
      masterKey,
      salt,
      info,
      keyLength
    );
  }

  // Decrypt legacy 3DES data
  decryptLegacy3DES(encryptedData, legacyKey, legacyIV) {
    try {
      const decipher = crypto.createDecipheriv(
        'des-ede3-cbc',
        Buffer.from(legacyKey, 'hex'),
        Buffer.from(legacyIV, 'hex')
      );

      let decrypted = decipher.update(encryptedData, 'base64', 'utf8');
      decrypted += decipher.final('utf8');

      this.config.auditLog.info('Legacy decryption successful', {
        algorithm: 'des-ede3-cbc',
        timestamp: new Date().toISOString()
      });

      return decrypted;
    } catch (error) {
      this.config.auditLog.error('Legacy decryption failed', {
        error: error.message,
        algorithm: 'des-ede3-cbc'
      });
      throw new Error('Legacy decryption failed');
    }
  }

  // Encrypt with modern AES-256-GCM
  encryptModern(plaintext, masterKey, context = 'migrated-data') {
    const salt = crypto.randomBytes(16);
    const iv = crypto.randomBytes(12);

    // Derive unique encryption key using HKDF
    const encryptionKey = this.deriveKey(
      masterKey,
      salt,
      `encryption:${context}`,
      32
    );

    const cipher = crypto.createCipheriv('aes-256-gcm', encryptionKey, iv);

    // Version and context as AAD
    const aad = Buffer.from(JSON.stringify({
      version: 2,
      context,
      migrated: new Date().toISOString()
    }));
    cipher.setAAD(aad);

    let encrypted = cipher.update(plaintext, 'utf8');
    encrypted = Buffer.concat([encrypted, cipher.final()]);
    const authTag = cipher.getAuthTag();

    // Format: version(1) + salt(16) + iv(12) + tag(16) + ciphertext
    const version = Buffer.from([0x02]);
    const result = Buffer.concat([version, salt, iv, authTag, encrypted]);

    return result.toString('base64');
  }

  // Decrypt modern format with version detection
  decryptModern(encryptedData, masterKey, context = 'migrated-data') {
    const buffer = Buffer.from(encryptedData, 'base64');

    const version = buffer[0];
    if (version !== 0x02) {
      throw new Error(`Unsupported encryption version: ${version}`);
    }

    const salt = buffer.subarray(1, 17);
    const iv = buffer.subarray(17, 29);
    const authTag = buffer.subarray(29, 45);
    const ciphertext = buffer.subarray(45);

    const encryptionKey = this.deriveKey(masterKey, salt, `encryption:${context}`, 32);

    const decipher = crypto.createDecipheriv('aes-256-gcm', encryptionKey, iv);
    decipher.setAuthTag(authTag);

    const aad = Buffer.from(JSON.stringify({
      version: 2,
      context,
      migrated: new Date().toISOString()
    }));
    decipher.setAAD(aad);

    let decrypted = decipher.update(ciphertext);
    decrypted = Buffer.concat([decrypted, decipher.final()]);

