        batch.map(record => this.migrateRecord(
          record,
          legacyKey,
          legacyIV,
          newMasterKey
        ))
      );

      batchResults.forEach((result, index) => {
        const record = batch[index];
        if (result.status === 'fulfilled') {
          results.success.push({
            id: record.id,
            newData: result.value
          });
        } else {
          results.failed.push({
            id: record.id,
            error: result.reason.message
          });
        }
      });

      this.emit('batchComplete', {
        batchIndex,
        successCount: batchResults.filter(r => r.status === 'fulfilled').length,
        failureCount: batchResults.filter(r => r.status === 'rejected').length
      });
    }

    this.config.auditLog.info('Migration completed', {
      total: results.total,
      success: results.success.length,
      failed: results.failed.length,
      timestamp: new Date().toISOString()
    });

    return results;
  }

  async migrateRecord(record, legacyKey, legacyIV, newMasterKey) {
    let retries = 0;

    while (retries < this.config.maxRetries) {
      try {
        // Step 1: Decrypt with legacy algorithm
        const plaintext = this.decryptLegacy3DES(
          record.encryptedData,
          legacyKey,
          legacyIV
        );

        // Step 2: Validate decrypted data
        this.validateDecryptedData(plaintext, record.expectedFormat);

        // Step 3: Re-encrypt with modern algorithm
        const newEncrypted = this.encryptModern(
          plaintext,
          newMasterKey,
          `record:${record.id}`
        );

        // Step 4: Verify round-trip
        const verification = this.decryptModern(
          newEncrypted,
          newMasterKey,
          `record:${record.id}`
        );

        if (verification !== plaintext) {
          throw new Error('Round-trip verification failed');
        }

        return {
          id: record.id,
          encryptedData: newEncrypted,
          algorithm: 'aes-256-gcm',
          version: 2,
          migratedAt: new Date().toISOString()
        };

      } catch (error) {
        retries++;
        if (retries >= this.config.maxRetries) {
          throw error;
        }
        await this.delay(100 * Math.pow(2, retries));
      }
    }
  }

  validateDecryptedData(data, expectedFormat) {
    if (expectedFormat === 'json') {
      try {
        JSON.parse(data);
      } catch {
        throw new Error('Decrypted data is not valid JSON');
      }
    }
    // Add more format validations as needed
  }

  chunkArray(array, size) {
    const chunks = [];
    for (let i = 0; i < array.length; i += size) {
      chunks.push(array.slice(i, i + size));
    }
    return chunks;
  }

  delay(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

// Key Management Service
class KeyManagementService {
  constructor(config) {
    this.config = config;
    this.keyCache = new Map();
    this.rotationInterval = config.rotationDays || 90;
  }

  // Generate master key with proper entropy
  static generateMasterKey() {
    const key = crypto.randomBytes(32);
    const keyId = crypto.randomUUID();

    return {
      keyId,
      key: key.toString('base64'),
      createdAt: new Date().toISOString(),
      algorithm: 'aes-256-gcm',
      status: 'active'
    };
  }

  // Envelope encryption for storing keys
  wrapKey(keyToWrap, wrappingKey) {
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', wrappingKey, iv);

    let wrapped = cipher.update(keyToWrap);
    wrapped = Buffer.concat([wrapped, cipher.final()]);
    const authTag = cipher.getAuthTag();

    return {
      wrappedKey: Buffer.concat([iv, authTag, wrapped]).toString('base64'),
      algorithm: 'aes-256-gcm-wrap'
    };
  }

  unwrapKey(wrappedData, wrappingKey) {
    const buffer = Buffer.from(wrappedData, 'base64');
    const iv = buffer.subarray(0, 12);
    const authTag = buffer.subarray(12, 28);
    const wrapped = buffer.subarray(28);

    const decipher = crypto.createDecipheriv('aes-256-gcm', wrappingKey, iv);
    decipher.setAuthTag(authTag);

    let unwrapped = decipher.update(wrapped);
    unwrapped = Buffer.concat([unwrapped, decipher.final()]);

    return unwrapped;
  }

  // Check if key needs rotation
  shouldRotateKey(keyMetadata) {
    const createdAt = new Date(keyMetadata.createdAt);
    const daysSinceCreation = (Date.now() - createdAt.getTime()) / (1000 * 60 * 60 * 24);
    return daysSinceCreation >= this.rotationInterval;
  }
}

