		return nil, errors.New("key must be 32 bytes for AES-256")
	}

	ciphertext, err := hex.DecodeString(ciphertextHex)
	if err != nil {
		return nil, fmt.Errorf("invalid ciphertext encoding: %w", err)
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, fmt.Errorf("failed to create cipher: %w", err)
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, fmt.Errorf("failed to create GCM: %w", err)
	}

	if len(ciphertext) < gcm.NonceSize() {
		return nil, errors.New("ciphertext too short")
	}

	nonce := ciphertext[:gcm.NonceSize()]
	ciphertext = ciphertext[gcm.NonceSize():]

	// Decrypt and verify authentication tag
	plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
	if err != nil {
		return nil, errors.New("decryption failed: authentication error")
	}

	return plaintext, nil
}
```

**Key Security Controls**:
- **AES-256-GCM**: Uses 128-bit block size (immune to birthday attacks until 2^64 blocks), 256-bit key strength
- **Authenticated Encryption**: GCM mode provides both confidentiality and integrity, preventing tampering
- **Unique Nonces**: Cryptographically random nonce for each encryption prevents nonce reuse attacks
- **NIST Approved**: AES-GCM is FIPS 140-2/3 compliant and approved for classified information

For production systems handling millions of records, you need proper key management, key rotation, envelope encryption, and monitoring. Here's a comprehensive implementation:

**PRODUCTION PATTERN**:

```go
package crypto

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"sync"
	"time"

	"golang.org/x/crypto/hkdf"
)

var (
	ErrInvalidKey       = errors.New("invalid encryption key")
	ErrDecryptionFailed = errors.New("decryption failed")
	ErrKeyExpired       = errors.New("encryption key has expired")
)

// KeyMetadata tracks key version and expiration for rotation
type KeyMetadata struct {
	KeyID     string
	Version   int
	CreatedAt time.Time
	ExpiresAt time.Time
	Algorithm string
}

// EncryptedData contains ciphertext with metadata for decryption
type EncryptedData struct {
	KeyID      string `json:"kid"`
	Version    int    `json:"v"`
	Ciphertext string `json:"ct"`
	CreatedAt  int64  `json:"ts"`
}

// KeyProvider interface for external key management (AWS KMS, HashiCorp Vault)
type KeyProvider interface {
	GetKey(ctx context.Context, keyID string) ([]byte, *KeyMetadata, error)
	GenerateDataKey(ctx context.Context, masterKeyID string) ([]byte, []byte, error)
	DecryptDataKey(ctx context.Context, encryptedKey []byte) ([]byte, error)
}

// SecureEncryptor provides production-grade encryption with key rotation
type SecureEncryptor struct {
	keyProvider    KeyProvider
	currentKeyID   string
	keyCache       map[string]*cachedKey
	cacheMutex     sync.RWMutex
	logger         *slog.Logger
	metricsEnabled bool
}

type cachedKey struct {
	key       []byte
	metadata  *KeyMetadata
	cachedAt  time.Time
	gcm       cipher.AEAD
}

// NewSecureEncryptor creates encryptor with key provider
func NewSecureEncryptor(provider KeyProvider, currentKeyID string, logger *slog.Logger) *SecureEncryptor {
	return &SecureEncryptor{
		keyProvider:    provider,
		currentKeyID:   currentKeyID,
		keyCache:       make(map[string]*cachedKey),
		logger:         logger,
		metricsEnabled: true,
	}
}

// Encrypt encrypts data using envelope encryption pattern
func (e *SecureEncryptor) Encrypt(ctx context.Context, plaintext []byte) (*EncryptedData, error) {
	startTime := time.Now()
	defer func() {
		if e.metricsEnabled {
			e.recordMetric("encrypt_duration_ms", float64(time.Since(startTime).Milliseconds()))
		}
	}()

	// Get or create data encryption key (DEK)
	cached, err := e.getCachedKey(ctx, e.currentKeyID)
	if err != nil {
		e.logger.Error("failed to get encryption key",
			slog.String("key_id", e.currentKeyID),
			slog.String("error", err.Error()))
		return nil, fmt.Errorf("encryption key unavailable: %w", err)
	}

	// Check key expiration
	if time.Now().After(cached.metadata.ExpiresAt) {
		e.logger.Warn("encryption key expired, rotation required",
			slog.String("key_id", e.currentKeyID))
		return nil, ErrKeyExpired
	}

	// Generate unique nonce for this encryption
	nonce := make([]byte, cached.gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		e.logger.Error("nonce generation failed", slog.String("error", err.Error()))
		return nil, fmt.Errorf("cryptographic error: %w", err)
	}

	// Encrypt with AES-256-GCM
	ciphertext := cached.gcm.Seal(nonce, nonce, plaintext, nil)

	e.logger.Debug("data encrypted successfully",
		slog.String("key_id", e.currentKeyID),
		slog.Int("plaintext_size", len(plaintext)))

	return &EncryptedData{
		KeyID:      e.currentKeyID,
		Version:    cached.metadata.Version,
		Ciphertext: base64.StdEncoding.EncodeToString(ciphertext),
		CreatedAt:  time.Now().Unix(),
	}, nil
}

// Decrypt decrypts data, supporting multiple key versions for rotation
func (e *SecureEncryptor) Decrypt(ctx context.Context, data *EncryptedData) ([]byte, error) {
	startTime := time.Now()
	defer func() {
		if e.metricsEnabled {
			e.recordMetric("decrypt_duration_ms", float64(time.Since(startTime).Milliseconds()))
		}
	}()

	// Get the specific key version used for encryption
	cached, err := e.getCachedKey(ctx, data.KeyID)
	if err != nil {
		e.logger.Error("decryption key unavailable",
			slog.String("key_id", data.KeyID),
			slog.String("error", err.Error()))
		return nil, fmt.Errorf("decryption key unavailable: %w", err)
	}

	ciphertext, err := base64.StdEncoding.DecodeString(data.Ciphertext)
	if err != nil {
		return nil, ErrDecryptionFailed
	}

	if len(ciphertext) < cached.gcm.NonceSize() {
		e.logger.Warn("invalid ciphertext length",
			slog.String("key_id", data.KeyID))
		return nil, ErrDecryptionFailed
	}

	nonce := ciphertext[:cached.gcm.NonceSize()]
	ciphertext = ciphertext[cached.gcm.NonceSize():]

	plaintext, err := cached.gcm.Open(nil, nonce, ciphertext, nil)
	if err != nil {
		e.logger.Warn("decryption authentication failed",
			slog.String("key_id", data.KeyID),
			slog.Int64("encrypted_at", data.CreatedAt))
		// Don't expose cryptographic details in error
		return nil, ErrDecryptionFailed
	}

	e.logger.Debug("data decrypted successfully",
		slog.String("key_id", data.KeyID))

	return plaintext, nil
}

// getCachedKey retrieves key from cache or fetches from provider
func (e *SecureEncryptor) getCachedKey(ctx context.Context, keyID string) (*cachedKey, error) {
	e.cacheMutex.RLock()
	cached, exists := e.keyCache[keyID]
	e.cacheMutex.RUnlock()

	// Return cached if fresh (cache for 5 minutes max)
	if exists && time.Since(cached.cachedAt) < 5*time.Minute {
		return cached, nil
	}

	// Fetch from key provider
	key, metadata, err := e.keyProvider.GetKey(ctx, keyID)
	if err != nil {
		return nil, err
	}

	// Derive encryption key using HKDF for additional security
	derivedKey := make([]byte, 32)
	kdf := hkdf.New(sha256.New, key, []byte(keyID), []byte("AES-256-GCM"))
	if _, err := io.ReadFull(kdf, derivedKey); err != nil {
		return nil, fmt.Errorf("key derivation failed: %w", err)
	}

	block, err := aes.NewCipher(derivedKey)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	newCached := &cachedKey{
		key:      derivedKey,
		metadata: metadata,
		cachedAt: time.Now(),
		gcm:      gcm,
	}

	e.cacheMutex.Lock()
	e.keyCache[keyID] = newCached
	e.cacheMutex.Unlock()

	return newCached, nil
}

// RotateKey triggers key rotation, re-encrypting data with new key
func (e *SecureEncryptor) RotateKey(ctx context.Context, newKeyID string) error {
	e.logger.Info("initiating key rotation",
		slog.String("old_key_id", e.currentKeyID),
		slog.String("new_key_id", newKeyID))

	// Verify new key is accessible
	_, err := e.getCachedKey(ctx, newKeyID)
	if err != nil {
		return fmt.Errorf("new key not accessible: %w", err)
	}

	oldKeyID := e.currentKeyID
	e.currentKeyID = newKeyID

	e.logger.Info("key rotation completed",
		slog.String("old_key_id", oldKeyID),
		slog.String("new_key_id", newKeyID))

	return nil
}

func (e *SecureEncryptor) recordMetric(name string, value float64) {
	// Integration point for Prometheus, DataDog, etc.
	e.logger.Debug("metric recorded",
		slog.String("name", name),
		slog.Float64("value", value))
}

// ClearKeyCache securely clears cached keys (call during shutdown)
func (e *SecureEncryptor) ClearKeyCache() {
	e.cacheMutex.Lock()
	defer e.cacheMutex.Unlock()

	for keyID, cached := range e.keyCache {
		// Zero out key material
		for i := range cached.key {
			cached.key[i] = 0
		}
		delete(e.keyCache, keyID)
	}

	e.logger.Info("key cache cleared securely")
}
