Excellent question! AES-CBC provides confidentiality but **NOT integrity or authenticity**. Without authentication, attackers can perform padding oracle attacks (like POODLE) or bit-flipping attacks to modify ciphertext. For production systems, you should use **Authenticated Encryption with Associated Data (AEAD)** - specifically AES-GCM.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace Production.Security.Encryption
{
    public interface IEncryptionService
    {
        string Encrypt(string plainText, string associatedData = null);
        string Decrypt(string cipherText, string associatedData = null);
    }

    /// <summary>
    /// Production-ready AES-256-GCM authenticated encryption service.
    /// Provides confidentiality, integrity, and authenticity.
    /// </summary>
    public sealed class AesGcmEncryptionService : IEncryptionService, IDisposable
    {
        private readonly byte[] _masterKey;
        private readonly ILogger<AesGcmEncryptionService> _logger;
        private readonly int _nonceSize = 12; // 96 bits recommended for GCM
        private readonly int _tagSize = 16;   // 128 bits authentication tag
        private bool _disposed = false;

        public AesGcmEncryptionService(
            IConfiguration configuration, 
            ILogger<AesGcmEncryptionService> logger)
        {
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));

            // Load key from secure key management (Azure Key Vault, AWS KMS, HashiCorp Vault)
            string keyBase64 = configuration["Security:Encryption:AesGcmKey"];
            if (string.IsNullOrEmpty(keyBase64))
            {
                _logger.LogCritical("Encryption key not configured - service cannot start");
                throw new InvalidOperationException("Encryption key not configured");
            }

            _masterKey = Convert.FromBase64String(keyBase64);
            ValidateKey(_masterKey);

            _logger.LogInformation("AES-GCM encryption service initialized");
        }

        private void ValidateKey(byte[] key)
        {
            if (key == null || key.Length != 32)
            {
                throw new CryptographicException("AES-256-GCM requires a 256-bit (32-byte) key");
            }
        }

        public string Encrypt(string plainText, string associatedData = null)
        {
            if (_disposed)
                throw new ObjectDisposedException(nameof(AesGcmEncryptionService));

            if (string.IsNullOrEmpty(plainText))
                throw new ArgumentNullException(nameof(plainText));

            try
            {
                byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
                byte[] aadBytes = string.IsNullOrEmpty(associatedData) 
                    ? Array.Empty<byte>() 
                    : Encoding.UTF8.GetBytes(associatedData);

                // Generate cryptographically secure random nonce
                byte[] nonce = new byte[_nonceSize];
                using (var rng = RandomNumberGenerator.Create())
                {
                    rng.GetBytes(nonce);
                }

                byte[] cipherText = new byte[plainBytes.Length];
                byte[] tag = new byte[_tagSize];

                using (var aesGcm = new AesGcm(_masterKey, _tagSize))
                {
                    aesGcm.Encrypt(nonce, plainBytes, cipherText, tag, aadBytes);
                }

                // Format: [nonce (12 bytes)][tag (16 bytes)][ciphertext]
                byte[] result = new byte[_nonceSize + _tagSize + cipherText.Length];
                Buffer.BlockCopy(nonce, 0, result, 0, _nonceSize);
                Buffer.BlockCopy(tag, 0, result, _nonceSize, _tagSize);
                Buffer.BlockCopy(cipherText, 0, result, _nonceSize + _tagSize, cipherText.Length);

                // Clear sensitive data from memory
                CryptographicOperations.ZeroMemory(plainBytes);

                return Convert.ToBase64String(result);
            }
            catch (CryptographicException ex)
            {
                _logger.LogError(ex, "Encryption failed - cryptographic error");
                throw new InvalidOperationException("Encryption operation failed", ex);
            }
        }

        public string Decrypt(string cipherText, string associatedData = null)
        {
            if (_disposed)
                throw new ObjectDisposedException(nameof(AesGcmEncryptionService));

            if (string.IsNullOrEmpty(cipherText))
                throw new ArgumentNullException(nameof(cipherText));

            try
            {
                byte[] fullCipher = Convert.FromBase64String(cipherText);

                if (fullCipher.Length < _nonceSize + _tagSize)
                {
                    _logger.LogWarning("Decryption failed - invalid ciphertext length");
                    throw new CryptographicException("Invalid ciphertext");
                }

                byte[] aadBytes = string.IsNullOrEmpty(associatedData) 
                    ? Array.Empty<byte>() 
                    : Encoding.UTF8.GetBytes(associatedData);

                // Extract components
                byte[] nonce = new byte[_nonceSize];
                byte[] tag = new byte[_tagSize];
                byte[] cipherBytes = new byte[fullCipher.Length - _nonceSize - _tagSize];

                Buffer.BlockCopy(fullCipher, 0, nonce, 0, _nonceSize);
                Buffer.BlockCopy(fullCipher, _nonceSize, tag, 0, _tagSize);
                Buffer.BlockCopy(fullCipher, _nonceSize + _tagSize, cipherBytes, 0, cipherBytes.Length);

                byte[] plainBytes = new byte[cipherBytes.Length];

                using (var aesGcm = new AesGcm(_masterKey, _tagSize))
                {
                    // This throws if authentication fails (tampering detected)
                    aesGcm.Decrypt(nonce, cipherBytes, tag, plainBytes, aadBytes);
                }

                string result = Encoding.UTF8.GetString(plainBytes);

                // Clear sensitive data from memory
                CryptographicOperations.ZeroMemory(plainBytes);

                return result;
            }
            catch (AuthenticationTagMismatchException)
            {
                _logger.LogWarning("Decryption failed - authentication tag mismatch (possible tampering)");
                throw new CryptographicException("Data integrity verification failed");
            }
            catch (CryptographicException ex)
            {
                _logger.LogError(ex, "Decryption failed - cryptographic error");
                throw new InvalidOperationException("Decryption operation failed", ex);
            }
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                // Securely clear the master key from memory
                if (_masterKey != null)
                {
                    CryptographicOperations.ZeroMemory(_masterKey);
                }
                _disposed = true;
            }
        }
    }

